class MetricsCollector:
    """Lightweight metrics collection for monitoring throughput."""
    
    def __init__(self):
        self._total_requests = 0
        self._total_latency_ns = 0
        self._start_time = time.time()
        self._errors = 0
    
    def record_request(self, latency_ns: int, error: bool = False):
        self._total_requests += 1
        self._total_latency_ns += latency_ns
        if error:
            self._errors += 1
    
    @property
    def total_requests(self) -> int:
        return self._total_requests
    
    @property
    def avg_latency_ms(self) -> float:
        if self._total_requests == 0:
            return 0.0
        return (self._total_latency_ns / self._total_requests) / 1_000_000
    
    @property
    def uptime_seconds(self) -> int:
        return int(time.time() - self._start_time)
    
    @property
    def requests_per_second(self) -> float:
        elapsed = time.time() - self._start_time
        if elapsed == 0:
            return 0.0
        return self._total_requests / elapsed


